const input = $input.first().json;

// ── TABLAS ─────────────────────────────────────────────
const duraciones = {
  "Masaje Relajante Con Aceites Esenciales 1 Hora": 60,
  "Masaje Relajante Con Aceites Esenciales 30Min": 30,
  "Masaje Relajante Con Aceites Esenciales 1H 30Min": 90,
  "Masaje Relajante Con Aceites Esenciales 2 Horas": 120,
  "Masaje Descontracturante 40Min": 40,
  "Masaje Descontracturante 1 Hora": 60,
  "Masaje Descontracturante 1H 30Min": 90,
  "Masaje Balsámico": 90,
  "Masaje Ayurveda Y Terapia Holística De Bienestar": 105,
  "Masaje Ayurveda Abhyanga 30Min": 30,
  "Masaje Ayurveda Abhyanga 1 Hora": 60,
  "Masaje Ayurveda Abhyanga 1H 30Min": 90,
  "Masaje Tailandés Con Aceites 30Min": 30,
  "Masaje Tailandés Con Aceites 1 Hora": 60,
  "Masaje Tailandés Con Aceites 1H 30Min": 90,
  "Masaje En Pareja 1 Hora": 60,
  "Masaje En Pareja 1H 30Min": 90,
  "Masaje En Pareja 2 Horas": 120,
};

const colores = {};
Object.keys(duraciones).forEach(k => colores[k] = "1");

// ── INPUT ─────────────────────────────────────────────
let fechaRaw = input.fecha || "";
let horaRaw  = input.hora  || "";

// Separar si viene junto
if (fechaRaw.includes(" ") && !horaRaw) {
  const partes = fechaRaw.split(" ");
  fechaRaw = partes[0];
  horaRaw  = partes[1];
}

if (!fechaRaw || !horaRaw) {
  throw new Error(`Faltan datos → fecha: "${fechaRaw}", hora: "${horaRaw}"`);
}

// ── FECHA ─────────────────────────────────────────────
const fecha = fechaRaw; // ya viene en formato correcto
const hora  = horaRaw;

// ── VALIDAR HORA ──────────────────────────────────────
const [horas, minutos] = hora.split(":").map(Number);
if (isNaN(horas) || isNaN(minutos)) {
  throw new Error(`Hora inválida: ${hora}`);
}

// ── LIMPIAR SERVICIO ──────────────────────────────────
let servicioRaw = input.servicio || "";
servicioRaw = servicioRaw.replace(/[()]/g, "").trim();

// buscar coincidencia
const servicio = Object.keys(duraciones).find(
  s => s.toLowerCase() === servicioRaw.toLowerCase()
) || servicioRaw;

// ── DURACIÓN Y COLOR ──────────────────────────────────
const duracion = duraciones[servicio] || 60;
const colorId  = colores[servicio]    || "1";

// ── CALCULAR FIN ──────────────────────────────────────
const totalMin = horas * 60 + minutos + duracion;
const horaFin  = String(Math.floor(totalMin / 60)).padStart(2, "0");
const minFin   = String(totalMin % 60).padStart(2, "0");

// ── OFFSET ESPAÑA ─────────────────────────────────────
const offset = "+01:00"; // simplificado (vale para ahora)

// ── FORMATO FINAL ─────────────────────────────────────
const start_time = `${fecha}T${hora}:00${offset}`;
const end_time   = `${fecha}T${horaFin}:${minFin}:00${offset}`;

// ── OUTPUT ────────────────────────────────────────────
return [{
  json: {
    ...input,
    fecha,
    hora,
    servicio,
    duracion,
    colorId,
    start: {
      dateTime: start_time
    },
    end: {
      dateTime: end_time
    }
  }
}];

